1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface QuoteStep {
8	  op: "quote";
9	  items: Item[];
10	}
11	
12	type Step = QuoteStep;
13	
14	interface Scenario {
15	  customer: { yearsWithMHPCO: number };
16	  steps: Step[];
17	}
18	
19	interface QuoteResult {
20	  premium: number;
21	}
22	
23	interface ScenarioOutput {
24	  results: QuoteResult[];
25	}
26	
27	const PROCESSING_FEE = 5;
28	const LOYALTY_DISCOUNT_RATE = 0.2;
29	const LOYALTY_THRESHOLD_YEARS = 2;
30	const COMPONENT_TYPES = ["rune", "moonstone"];
31	const BLOCK_SIZE = 3;
32	const BLOCK_PREMIUM = 60;
33	const CURSE_SURCHARGE_RATE = 0.5;
34	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
35	const HIGH_ENCHANTMENT_THRESHOLD = 5;
36	
37	const BASE_PREMIUMS: Record<string, number> = {
38	  sword: 100,
39	  amulet: 60,
40	  staff: 80,
41	  potion: 40,
42	  rune: 25,
43	  moonstone: 25,
44	};
45	
46	const isComponent = (item: Item): boolean =>
47	  COMPONENT_TYPES.includes(item.type);
48	
49	const calculateItemPremium = (item: Item): number => {
50	  const base = BASE_PREMIUMS[item.type] ?? 0;
51	  let premium = base;
52	  if (item.cursed) {
53	    premium += base * CURSE_SURCHARGE_RATE;
54	  }
55	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
56	    premium += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
57	  }
58	  return premium;
59	};
60	
61	const calculateComponentPremium = (
62	  componentCounts: Record<string, number>,
63	): number => {
64	  let total = 0;
65	  for (const [type, count] of Object.entries(componentCounts)) {
66	    total +=
67	      count === BLOCK_SIZE
68	        ? BLOCK_PREMIUM
69	        : count * (BASE_PREMIUMS[type] ?? 0);
70	  }
71	  return total;
72	};
73	
74	export function processScenario(scenario: Scenario): ScenarioOutput {
75	  const results = scenario.steps.map((step) => {
76	    const componentCounts: Record<string, number> = {};
77	    let totalBeforeFee = 0;
78	
79	    for (const item of step.items) {
80	      if (isComponent(item)) {
81	        componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
82	      } else {
83	        totalBeforeFee += calculateItemPremium(item);
84	      }
85	    }
86	
87	    totalBeforeFee += calculateComponentPremium(componentCounts);
88	
89	    const policyBase = totalBeforeFee;
90	
91	    // Policy-wide modifiers (all percentages of policyBase)
92	    totalBeforeFee += policyBase * 0.1; // first-insurance surcharge (always applies)
93	
94	    if (scenario.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
95	      totalBeforeFee -= policyBase * LOYALTY_DISCOUNT_RATE;
96	    }
97	
98	    const finalPremium = totalBeforeFee + PROCESSING_FEE;
99	    return { premium: Math.ceil(parseFloat(finalPremium.toFixed(10))) };
100	  });
101	  return { results };
102	}
